 39	static void _event(void *p, event e)
 40	{
 41	  struct textlog *l = p;
 42	  int i, j;
 43	#ifdef T_SEND_TIME
 44	  struct tm *t;
 45	  char tt[64];
 46	#endif
 47	
 48	  if (l->common.filter != NULL && filter_eval(l->common.filter, e) == 0)
 49	    return;
 50	
 51	  l->o.osize = 0;
 52	
 53	#ifdef T_SEND_TIME
 54	  t = localtime(&e.sending_time.tv_sec);
 55	  if (l->raw_time)
 56	    sprintf(tt, "%2.2d:%2.2d:%2.2d.%9.9ld [%ld]: ",
 57	        t->tm_hour, t->tm_min, t->tm_sec,
 58	        e.sending_time.tv_nsec, e.sending_time.tv_sec);
 59	  else
 60	    sprintf(tt, "%2.2d:%2.2d:%2.2d.%9.9ld: ", t->tm_hour, t->tm_min, t->tm_sec,
 61	        e.sending_time.tv_nsec);
 62	  PUTS(&l->o, tt);
 63	#endif
 64	
 65	  for (i = 0; i < l->fsize; i++)
 66	  switch(l->f[i].type) {
 67	  case INSTRING: PUTS(&l->o, l->f[i].s); break;
 68	  case INT:      PUTI(&l->o, e.e[l->f[i].event_arg].i); break;
 69	  case ULONG:    PUTUL(&l->o, e.e[l->f[i].event_arg].ul); break;
 70	  case STRING:   PUTS_CLEAN(&l->o, e.e[l->f[i].event_arg].s); break;
 71	  case BUFFER:
 72	    PUTS(&l->o, "{buffer size:");
 73	    PUTI(&l->o, e.e[l->f[i].event_arg].bsize);
 74	    if (l->dump_buffer) {
 75	      PUTS(&l->o, " [");
 76	      for (j = 0; j < e.e[l->f[i].event_arg].bsize; j++) {
 77	        PUTX2(&l->o, ((unsigned char *)e.e[l->f[i].event_arg].b)[j]);
 78	        PUTC(&l->o, ' ');
 79	      }
 80	      PUTS(&l->o, "]");
 81	    }
 82	    PUTS(&l->o, "}");
 83	    break;
 84	  }
 85	  PUTC(&l->o, 0);
 86	
 87	  for (i = 0; i < l->common.vsize; i++)
 88	    l->common.v[i]->append(l->common.v[i], l->o.obuf);
 89	}
