 99	/* TODO: speed it up? */
100	static int find_argument(char *name, database_event_format f,
101	    enum format_item_type *it, int *event_arg)
102	{
103	  int i;
104	  for (i = 0; i < f.count; i++) if (!strcmp(name, f.name[i])) break;
105	  if (i == f.count) return 0;
106	  *event_arg = i;
107	  if (!strcmp(f.type[i], "int"))         *it = INT;
108	  else if (!strcmp(f.type[i], "ulong"))  *it = ULONG;
109	  else if (!strcmp(f.type[i], "string")) *it = STRING;
110	  else if (!strcmp(f.type[i], "buffer")) *it = BUFFER;
111	  else return 0;
112	  return 1;
113	}
114	
115	static struct chunk next_chunk(char **s, database_event_format f)
116	{
117	  char *cur = *s;
118	  char *name;
119	  enum format_item_type it;
120	  int event_arg;
121	
122	  /* argument in [ ] */
123	  if (*cur == '[') {
124	    *cur = 0;
125	    cur++;
126	    name = cur;
127	    /* no \ allowed there */
128	    while (*cur && *cur != ']' && *cur != '\\') cur++;
129	    if (*cur != ']') goto error;
130	    *cur = 0;
131	    cur++;
132	    *s = cur;
133	    if (find_argument(name, f, &it, &event_arg) == 0) goto error;
134	    return (struct chunk){type:C_ARG_NAME, s:name, it:it, event_arg:event_arg};
135	  }
136	
137	  /* { } is name of event (anything in between is smashed) */
138	  if (*cur == '{') {
139	    *cur = 0;
140	    cur++;
141	    while (*cur && *cur != '}') cur++;
142	    if (*cur != '}') goto error;
143	    *cur = 0;
144	    cur++;
145	    *s = cur;
146	    return (struct chunk){type:C_EVENT_NAME};
147	  }
148	
149	  /* anything but [ and { is raw string */
150	  /* TODO: deal with \ */
151	  name = cur;
152	  while (*cur && *cur != '[' && *cur != '{') cur++;
153	  *s = cur;
154	  return (struct chunk){type:C_STRING, s:name};
155	
156	error:
157	  return (struct chunk){type:C_ERROR};
158	}
